   169→   * Return a sorted vector of registered factory names.
   170→   */
   171→  static std::vector<absl::string_view> registeredNames(bool include_disabled = false) {
   172→    std::vector<absl::string_view> ret;
   173→
   174→    ret.reserve(factories().size());
   175→
   176→    for (const auto& [factory_name, factory] : factories()) {
   177→      if (factory || include_disabled) {
   178→        ret.push_back(factory_name);
   179→      }
   180→    }
   181→
   182→    std::sort(ret.begin(), ret.end());
   183→
   184→    return ret;
   185→  }
   186→
   187→  /**
   188→   * Gets the current map of factory implementations.
   189→   */
   190→  static absl::flat_hash_map<std::string, Base*>& factories() {
   191→    static auto* factories = new absl::flat_hash_map<std::string, Base*>;
   192→    return *factories;
   193→  }
