   222→  static bool& allowDuplicates() {
   223→    static bool* allow_duplicates = new bool(false);
   224→    return *allow_duplicates;
   225→  }
   226→
   227→  /**
   228→   * instead_value are used when passed name was deprecated.
   229→   */
   230→  static void registerFactory(Base& factory, absl::string_view name,
